use aiki::editors::codex::otel::{
    any_value, AnyValue, ArrayValue, ExportLogsServiceRequest, InstrumentationScope, KeyValue,
    KeyValueList, LogRecord, Resource, ScopeLogs,
};
use prost::Message;
