// --- END OTLP TRACE SAMPLE ---
fn main() {
    let mut args: Vec<String> = env::args().skip(1).collect();
    let json_mode = args.first().map(|arg| arg == "--json").unwrap_or(false);
    if json_mode {
        args.remove(0);
    }

    let path = match args.first() {
        Some(p) => p,
        None => {
            eprintln!("Usage: otel_decode [--json] <path-to-otlp.bin>");
            std::process::exit(2);
        }
    };

    let data = match fs::read(&path) {
        Ok(d) => d,
        Err(e) => {
            eprintln!("Failed to read {}: {}", path, e);
            std::process::exit(1);
        }
    };

    println!("File: {} ({} bytes)", path, data.len());

    if json_mode {
        if let Ok(req) = ExportLogsServiceRequest::decode(data.as_slice()) {
            let value = logs_to_json(&req);
            print_json(&value);
            return;
        }
        if let Ok(req) = ExportTraceServiceRequest::decode(data.as_slice()) {
            let value = traces_to_json(&req);
            print_json(&value);
            return;
        }
        if let Ok(req) = ExportMetricsServiceRequest::decode(data.as_slice()) {
            let value = metrics_to_json(&req);
            print_json(&value);
            return;
        }

        eprintln!("No decodable OTLP payload");
        std::process::exit(1);
    } else {
        match ExportLogsServiceRequest::decode(data.as_slice()) {
            Ok(req) => summarize_logs(&req),
            Err(e) => println!("Logs decode error: {}", e),
        }

        match ExportTraceServiceRequest::decode(data.as_slice()) {
            Ok(req) => summarize_traces(&req),
            Err(e) => println!("Traces decode error: {}", e),
        }

        match ExportMetricsServiceRequest::decode(data.as_slice()) {
            Ok(req) => summarize_metrics(&req),
            Err(e) => println!("Metrics decode error: {}", e),
        }
    }
}

fn print_json(value: &Value) {
    let raw = serde_json::to_string_pretty(value).unwrap_or_else(|_| "{}".to_string());
    println!("{}", escape_non_ascii(&raw));
}

fn escape_non_ascii(input: &str) -> String {
    let mut out = String::with_capacity(input.len());
    for ch in input.chars() {
        if ch.is_ascii() {
            out.push(ch);
        } else {
            let code = ch as u32;
            if code <= 0xFFFF {
                out.push_str(&format!("\\u{:04x}", code));
            } else {
                let code = code - 0x10000;
                let high = 0xD800 + ((code >> 10) & 0x3FF);
                let low = 0xDC00 + (code & 0x3FF);
                out.push_str(&format!("\\u{:04x}\\u{:04x}", high, low));
            }
        }
    }
    out
}

fn summarize_logs(req: &ExportLogsServiceRequest) {
    let mut record_count = 0usize;
    let mut event_names = BTreeSet::new();
    let mut attribute_keys = BTreeSet::new();

    for resource_logs in &req.resource_logs {
        for scope_logs in &resource_logs.scope_logs {
            for record in &scope_logs.log_records {
                record_count += 1;
                if let Some(name) = log_record_event_name(record) {
                    event_names.insert(name);
                }
                for kv in &record.attributes {
                    attribute_keys.insert(kv.key.clone());
                }
            }
        }
    }

    println!(
        "Logs: resource_logs={}, log_records={}, event_names={}",
        req.resource_logs.len(),
        record_count,
        event_names.len()
    );
    if !event_names.is_empty() {
        println!(
            "  Event names (sample): {:?}",
            event_names.iter().take(10).collect::<Vec<_>>()
        );
    }
    if !attribute_keys.is_empty() {
        println!(
            "  Attribute keys (sample): {:?}",
            attribute_keys.iter().take(12).collect::<Vec<_>>()
        );
    }
}

fn logs_to_json(req: &ExportLogsServiceRequest) -> Value {
    let resource_logs = req
        .resource_logs
        .iter()
        .map(|resource_logs| {
            let mut obj = Map::new();
            obj.insert(
                "resource".to_string(),
                resource_logs
                    .resource
                    .as_ref()
                    .map(resource_to_json)
                    .unwrap_or(Value::Null),
            );
            obj.insert(
                "scope_logs".to_string(),
                Value::Array(
                    resource_logs
                        .scope_logs
                        .iter()
                        .map(scope_logs_to_json)
                        .collect(),
                ),
            );
            Value::Object(obj)
        })
        .collect();

    let mut root = Map::new();
    root.insert("resource_logs".to_string(), Value::Array(resource_logs));
    Value::Object(root)
}

fn scope_logs_to_json(scope_logs: &ScopeLogs) -> Value {
    let mut obj = Map::new();
    obj.insert(
        "scope".to_string(),
        scope_logs
            .scope
            .as_ref()
            .map(instrumentation_scope_to_json)
            .unwrap_or(Value::Null),
    );
    obj.insert(
        "log_records".to_string(),
        Value::Array(
            scope_logs
                .log_records
                .iter()
                .map(log_record_to_json)
                .collect(),
        ),
    );
    Value::Object(obj)
}

fn log_record_to_json(record: &LogRecord) -> Value {
    let mut obj = Map::new();
    obj.insert(
        "time_unix_nano".to_string(),
        Value::String(record.time_unix_nano.to_string()),
    );
    obj.insert(
        "observed_time_unix_nano".to_string(),
        Value::String(record.observed_time_unix_nano.to_string()),
    );
    obj.insert(
        "severity_number".to_string(),
        Value::Number(Number::from(record.severity_number)),
    );
    obj.insert(
        "severity_text".to_string(),
        Value::String(record.severity_text.clone()),
    );
    obj.insert(
        "body".to_string(),
        record
            .body
            .as_ref()
            .map(any_value_to_json)
            .unwrap_or(Value::Null),
    );
    obj.insert(
        "attributes".to_string(),
        Value::Array(record.attributes.iter().map(key_value_to_json).collect()),
    );
    obj.insert(
        "flags".to_string(),
        Value::Number(Number::from(record.flags)),
    );
    obj.insert(
        "trace_id".to_string(),
        Value::String(bytes_to_hex(&record.trace_id)),
    );
    obj.insert(
        "span_id".to_string(),
        Value::String(bytes_to_hex(&record.span_id)),
    );
    Value::Object(obj)
}

fn summarize_traces(req: &ExportTraceServiceRequest) {
    let mut span_count = 0usize;
    let mut event_count = 0usize;
    let mut span_names = BTreeSet::new();
    let mut event_names = BTreeSet::new();
    let mut attribute_keys = BTreeSet::new();

    for resource_spans in &req.resource_spans {
        for scope_spans in &resource_spans.scope_spans {
            for span in &scope_spans.spans {
                span_count += 1;
                if !span.name.is_empty() {
                    span_names.insert(span.name.clone());
                }
                for kv in &span.attributes {
                    attribute_keys.insert(kv.key.clone());
                }
                for event in &span.events {
                    event_count += 1;
                    if !event.name.is_empty() {
                        event_names.insert(event.name.clone());
                    }
                    for kv in &event.attributes {
                        attribute_keys.insert(kv.key.clone());
                    }
                }
            }
        }
    }

    println!(
        "Traces: resource_spans={}, spans={}, events={}",
        req.resource_spans.len(),
        span_count,
        event_count
    );
    if !span_names.is_empty() {
        println!(
            "  Span names (sample): {:?}",
            span_names.iter().take(10).collect::<Vec<_>>()
        );
    }
    if !event_names.is_empty() {
        println!(
            "  Event names (sample): {:?}",
            event_names.iter().take(10).collect::<Vec<_>>()
        );
    }
    if !attribute_keys.is_empty() {
        println!(
            "  Attribute keys (sample): {:?}",
            attribute_keys.iter().take(12).collect::<Vec<_>>()
        );
    }
}

fn traces_to_json(req: &ExportTraceServiceRequest) -> Value {
    let resource_spans = req
        .resource_spans
        .iter()
        .map(|resource_spans| {
            let mut obj = Map::new();
            obj.insert(
                "resource".to_string(),
                resource_spans
                    .resource
                    .as_ref()
                    .map(resource_to_json)
                    .unwrap_or(Value::Null),
            );
            obj.insert(
                "scope_spans".to_string(),
                Value::Array(
                    resource_spans
                        .scope_spans
                        .iter()
                        .map(scope_spans_to_json)
                        .collect(),
                ),
            );
            Value::Object(obj)
        })
        .collect();

    let mut root = Map::new();
    root.insert("resource_spans".to_string(), Value::Array(resource_spans));
    Value::Object(root)
}

