fn key_value_to_json(kv: &KeyValue) -> Value {
    let mut obj = Map::new();
    obj.insert("key".to_string(), Value::String(kv.key.clone()));
    obj.insert(
        "value".to_string(),
        kv.value
            .as_ref()
            .map(any_value_to_json)
            .unwrap_or(Value::Null),
    );
    Value::Object(obj)
}

fn any_value_to_json(value: &AnyValue) -> Value {
    match &value.value {
        Some(any_value::Value::StringValue(s)) => Value::String(s.clone()),
        Some(any_value::Value::BoolValue(b)) => Value::Bool(*b),
        Some(any_value::Value::IntValue(i)) => Value::Number(Number::from(*i)),
        Some(any_value::Value::DoubleValue(f)) => Number::from_f64(*f)
            .map(Value::Number)
            .unwrap_or(Value::Null),
        Some(any_value::Value::ArrayValue(array)) => array_value_to_json(array),
        Some(any_value::Value::KvlistValue(list)) => kvlist_to_json(list),
        Some(any_value::Value::BytesValue(bytes)) => Value::Array(
            bytes
                .iter()
                .map(|b| Value::Number(Number::from(*b)))
                .collect(),
        ),
        None => Value::Null,
    }
}

fn array_value_to_json(array: &ArrayValue) -> Value {
    Value::Array(array.values.iter().map(any_value_to_json).collect())
}

fn kvlist_to_json(list: &KeyValueList) -> Value {
    Value::Array(list.values.iter().map(key_value_to_json).collect())
}

fn bytes_to_hex(bytes: &[u8]) -> String {
    const HEX: &[u8; 16] = b"0123456789abcdef";
    let mut out = String::with_capacity(bytes.len() * 2);
    for byte in bytes {
        out.push(HEX[(byte >> 4) as usize] as char);
        out.push(HEX[(byte & 0x0f) as usize] as char);
    }
    out
}

fn log_record_event_name(record: &LogRecord) -> Option<String> {
    let body_name = record.body.as_ref().and_then(|body| match &body.value {
        Some(aiki::editors::codex::otel::any_value::Value::StringValue(s)) => Some(s.clone()),
        _ => None,
    });

    body_name
        .or_else(|| get_string_attribute(&record.attributes, "event.name"))
        .or_else(|| get_string_attribute(&record.attributes, "name"))
}

fn get_string_attribute(attributes: &[KeyValue], key: &str) -> Option<String> {
    attributes.iter().find(|kv| kv.key == key).and_then(|kv| {
        kv.value.as_ref().and_then(|v| {
            if let Some(aiki::editors::codex::otel::any_value::Value::StringValue(s)) = &v.value {
                Some(s.clone())
            } else {
                None
            }
        })
    })
}
